import heapq

class Solution:
    def kWeakestRows(self, mat: list[list[int]], k: int) -> list[int]:
        min_heap = []

        for i, row in enumerate(mat):
            strength = sum(row)

            heapq.heappush(min_heap, (-strength, -i))

            if len(min_heap) > k:
                heapq.heappop(min_heap)

        extracted_rows_data = []
        while min_heap:
            neg_s, neg_i = heapq.heappop(min_heap)
            extracted_rows_data.append((-neg_s, -neg_i))

        extracted_rows_data.reverse()

        return [index for strength, index in extracted_rows_data]
